public class NacosMd5Comparator implements Md5Comparator {

    @Override
    public String getName() {
        return "nacos";
    }

    @Override
    public Map<String, ConfigListenState> compareMd5(HttpServletRequest request,
        HttpServletResponse response,
        Map<String, ConfigListenState> clientMd5Map) {
        HashMap<String, ConfigListenState> changedGroupKeys = new HashMap<>(clientMd5Map.size());
        String tag = request.getHeader(VIPSERVER_TAG);
        for (Map.Entry<String, ConfigListenState> entry : clientMd5Map.entrySet()) {
            String groupKey = entry.getKey();
            String clientMd5 = entry.getValue().getMd5();
            String ip = RequestUtil.getRemoteIp(request);
            boolean isUptodate = ConfigCacheService.isUptodate(groupKey, clientMd5, ip, tag);
            if (!isUptodate) {
                changedGroupKeys.put(entry.getKey(), entry.getValue());
            }
        }
        return changedGroupKeys;
    }
}

public class AllocateMessageQueueAveragelyByCircle extends AbstractAllocateMessageQueueStrategy {

    @Override
    public List<MessageQueue> allocate(String consumerGroup, String currentCID, List<MessageQueue> mqAll,
        List<String> cidAll) {

        List<MessageQueue> result = new ArrayList<>();
        if (!check(consumerGroup, currentCID, mqAll, cidAll)) {
            return result;
        }

        int index = cidAll.indexOf(currentCID);
        for (int i = index; i < mqAll.size(); i++) {
            if (i % cidAll.size() == index) {
                result.add(mqAll.get(i));
            }
        }
        return result;
    }

    @Override
    public String getName() {
        return "AVG_BY_CIRCLE";
    }
}

public class FastJsonSerializer implements Serializer {

    @Override
    public <T> byte[] serialize(T t) throws SerializationException {
        if (t == null) {
            return new byte[0];
        } else {
            try {
                return JSON.toJSONBytes(t);
            } catch (Exception var3) {
                throw new SerializationException("Could not serialize: " + var3.getMessage(), var3);
            }
        }
    }

    @Override
    public <T> T deserialize(byte[] bytes, Class<T> type) throws SerializationException {
        if (bytes != null && bytes.length != 0) {
            try {
                return JSON.parseObject(bytes, type);
            } catch (Exception var3) {
                throw new SerializationException("Could not deserialize: " + var3.getMessage(), var3);
            }
        } else {
            return null;
        }
    }
}

public class TopicRouteHelper {

    public static boolean isTopicNotExistError(Throwable e) {
        if (e instanceof MQBrokerException) {
            if (((MQBrokerException) e).getResponseCode() == ResponseCode.TOPIC_NOT_EXIST) {
                return true;
            }
        }

        if (e instanceof MQClientException) {
            int code = ((MQClientException) e).getResponseCode();
            if (code == ResponseCode.TOPIC_NOT_EXIST || code == ClientErrorCode.NOT_FOUND_TOPIC_EXCEPTION) {
                return true;
            }

            Throwable cause = e.getCause();
            if (cause instanceof MQClientException) {
                int causeCode = ((MQClientException) cause).getResponseCode();
                return causeCode == ResponseCode.TOPIC_NOT_EXIST || causeCode == ClientErrorCode.NOT_FOUND_TOPIC_EXCEPTION;
            }
        }

        return false;
    }
}

public static String repeat(String string, int count) {
  checkNotNull(string); // eager for GWT.

  if (count <= 1) {
    checkArgument(count >= 0, "invalid count: %s", count);
    return (count == 0) ? "" : string;
  }

  // IF YOU MODIFY THE CODE HERE, you must update StringsRepeatBenchmark
  int len = string.length();
  long longSize = (long) len * (long) count;
  int size = (int) longSize;
  if (size != longSize) {
    throw new ArrayIndexOutOfBoundsException("Required array size too large: " + longSize);
  }

  char[] array = new char[size];
  string.getChars(0, len, array, 0);
  int n;
  for (n = len; n < size - n; n <<= 1) {
    arraycopy(array, 0, array, n, n);
  }
  arraycopy(array, 0, array, n, size - n);
  return new String(array);
}

private static String canonicalizeForPath(String input, boolean alreadyEncoded) {
  int codePoint;
  for (int i = 0, limit = input.length(); i < limit; i += Character.charCount(codePoint)) {
    codePoint = input.codePointAt(i);
    if (codePoint < 0x20
        || codePoint >= 0x7f
        || PATH_SEGMENT_ALWAYS_ENCODE_SET.indexOf(codePoint) != -1
        || (!alreadyEncoded && (codePoint == '/' || codePoint == '%'))) {
      // Slow path: the character at i requires encoding!
      Buffer out = new Buffer();
      out.writeUtf8(input, 0, i);
      canonicalizeForPath(out, input, i, limit, alreadyEncoded);
      return out.readUtf8();
    }
  }

  // Fast path: no characters required encoding.
  return input;
}

public static PropertyName merge(PropertyName name1, PropertyName name2) {
    if (name1 == null) {
        return name2;
    }
    if (name2 == null) {
        return name1;
    }
    // 22-Jun-2024, tatu: [databind#4595] Should not merge NO_NAME
    if (name1 == NO_NAME) {
        return name1;
    }
    String ns = _nonEmpty(name1._namespace, name2._namespace);
    String simple = _nonEmpty(name1._simpleName, name2._simpleName);

    // But see if we can just return one of arguments as-is:
    if (ns == name1._namespace && simple == name1._simpleName) {
        return name1;
    }
    if (ns == name2._namespace && simple == name2._simpleName) {
        return name2;
    }
    return construct(simple, ns);
}

