public abstract class AbstractNacosWebBeanTypeFilter implements TypeFilter {

    private static final Set<String> WEB_BEAN_ANNOTATIONS = new HashSet<>();

    static {
        WEB_BEAN_ANNOTATIONS.add(RestController.class.getCanonicalName());
        WEB_BEAN_ANNOTATIONS.add(ControllerAdvice.class.getCanonicalName());
        WEB_BEAN_ANNOTATIONS.add(Controller.class.getCanonicalName());
        WEB_BEAN_ANNOTATIONS.add(NacosWebBean.class.getCanonicalName());
    }

    protected boolean isWebBean(MetadataReader metadataReader,
        MetadataReaderFactory metadataReaderFactory)
        throws IOException {
        for (String each : WEB_BEAN_ANNOTATIONS) {
            if (metadataReader.getAnnotationMetadata().hasAnnotation(each)) {
                return true;
            }
        }
        return false;
    }
}

@Provider
@Priority(Priorities.ENTITY_CODER)
public class ConfiguredGZipEncoder implements WriterInterceptor, ClientRequestFilter {
    private boolean forceEncoding = false;

    public ConfiguredGZipEncoder(boolean forceEncoding) {
        this.forceEncoding = forceEncoding;
    }

    @Override
    public void filter(ClientRequestContext context) throws IOException {
        if (context.hasEntity() && context.getHeaders().getFirst(HttpHeaders.CONTENT_ENCODING) == null && this.forceEncoding) {
            context.getHeaders().add(HttpHeaders.CONTENT_ENCODING, "gzip");
        }
    }

    @Override
    public final void aroundWriteTo(WriterInterceptorContext context) throws IOException {
        final String contentEncoding = (String) context.getHeaders().getFirst(HttpHeaders.CONTENT_ENCODING);
        if ((contentEncoding != null) &&
                (contentEncoding.equals("gzip") || contentEncoding.equals("x-gzip"))) {
            context.setOutputStream(new GZIPOutputStream(context.getOutputStream()));
        }
        context.proceed();
    }

}

